import fs from 'fs';
import path from 'path';

const files = {
  "index.html": "<!doctype html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <title>My Google AI Studio App</title>\n  </head>\n  <body>\n    <div id=\"root\"></div>\n    <script type=\"module\" src=\"/src/main.tsx\"></script>\n  </body>\n</html>\n\n",
  "src/main.tsx": "import {StrictMode} from 'react';\nimport {createRoot} from 'react-dom/client';\nimport App from './App.tsx';\nimport './index.css';\n\ncreateRoot(document.getElementById('root')!).render(\n  <StrictMode>\n    <App />\n  </StrictMode>,\n);\n",
  "src/App.tsx": "import React from 'react';\nimport { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';\nimport { AuthProvider, useAuth } from './context/AuthContext';\nimport Layout from './components/Layout';\nimport Home from './pages/Home';\nimport Login from './pages/Login';\nimport Register from './pages/Register';\nimport Dashboard from './pages/Dashboard';\nimport AdminDashboard from './pages/AdminDashboard';\nimport CourseView from './pages/CourseView';\nimport ModuleView from './pages/ModuleView';\nimport Donate from './pages/Donate';\n\nconst PrivateRoute = ({ children, roles }: { children: React.ReactNode, roles?: string[] }) => {\n  const { user } = useAuth();\n  if (!user) return <Navigate to=\"/login\" />;\n  if (roles && !roles.includes(user.role)) return <Navigate to=\"/dashboard\" />;\n  return <>{children}</>;\n};\n\nexport default function App() {\n  return (\n    <AuthProvider>\n      <Router>\n        <Routes>\n          <Route path=\"/\" element={<Layout />}>\n            <Route index element={<Home />} />\n            <Route path=\"login\" element={<Login />} />\n            <Route path=\"register\" element={<Register />} />\n            <Route path=\"donate\" element={<Donate />} />\n            \n            <Route path=\"dashboard\" element={\n              <PrivateRoute>\n                <Dashboard />\n              </PrivateRoute>\n            } />\n            \n            <Route path=\"admin\" element={\n              <PrivateRoute roles={['admin', 'discipler']}>\n                <AdminDashboard />\n              </PrivateRoute>\n            } />\n\n            <Route path=\"courses/:id\" element={\n              <PrivateRoute>\n                <CourseView />\n              </PrivateRoute>\n            } />\n\n            <Route path=\"modules/:id\" element={\n              <PrivateRoute>\n                <ModuleView />\n              </PrivateRoute>\n            } />\n          </Route>\n        </Routes>\n      </Router>\n    </AuthProvider>\n  );\n}\n",
  "src/index.css": "@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Playfair+Display:ital,wght@0,400;0,700;1,400&display=swap');\n@import \"tailwindcss\";\n\n@theme {\n  --font-sans: \"Inter\", ui-sans-serif, system-ui, sans-serif;\n  --font-serif: \"Playfair Display\", ui-serif, Georgia, Cambria, \"Times New Roman\", Times, serif;\n}\n",
  "src/components/Layout.tsx": "import React from 'react';\nimport { Outlet, Link, useNavigate } from 'react-router-dom';\nimport { useAuth } from '../context/AuthContext';\nimport { BookOpen, LogOut, User as UserIcon, Settings, Home } from 'lucide-react';\n\nexport default function Layout() {\n  const { user, logout } = useAuth();\n  const navigate = useNavigate();\n\n  const handleLogout = () => {\n    logout();\n    navigate('/login');\n  };\n\n  return (\n    <div className=\"min-h-screen bg-neutral-50 flex flex-col font-sans text-neutral-900\">\n      <header className=\"bg-white border-b border-neutral-200 sticky top-0 z-10\">\n        <div className=\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8\">\n          <div className=\"flex justify-between h-16\">\n            <div className=\"flex\">\n              <Link to=\"/\" className=\"flex-shrink-0 flex items-center gap-2\">\n                <BookOpen className=\"h-8 w-8 text-emerald-600\" />\n                <span className=\"font-bold text-xl tracking-tight text-neutral-900\">\n                  VCLBC Discipleship\n                </span>\n              </Link>\n            </div>\n            <div className=\"flex items-center gap-4\">\n              {user ? (\n                <>\n                  <Link to=\"/donate\" className=\"text-emerald-600 hover:text-emerald-700 px-3 py-2 rounded-md text-sm font-medium transition-colors\">\n                    Donate\n                  </Link>\n                  <Link to=\"/dashboard\" className=\"text-neutral-500 hover:text-neutral-900 px-3 py-2 rounded-md text-sm font-medium transition-colors\">\n                    Dashboard\n                  </Link>\n                  {(user.role === 'admin' || user.role === 'discipler') && (\n                    <Link to=\"/admin\" className=\"text-neutral-500 hover:text-neutral-900 px-3 py-2 rounded-md text-sm font-medium transition-colors\">\n                      Admin\n                    </Link>\n                  )}\n                  <div className=\"flex items-center gap-2 ml-4 pl-4 border-l border-neutral-200\">\n                    <span className=\"text-sm font-medium text-neutral-700\">{user.name}</span>\n                    <button\n                      onClick={handleLogout}\n                      className=\"p-2 text-neutral-400 hover:text-red-600 transition-colors rounded-full hover:bg-neutral-100\"\n                      title=\"Logout\"\n                    >\n                      <LogOut className=\"h-5 w-5\" />\n                    </button>\n                  </div>\n                </>\n              ) : (\n                <>\n                  <Link to=\"/donate\" className=\"text-emerald-600 hover:text-emerald-700 px-3 py-2 rounded-md text-sm font-medium transition-colors\">\n                    Donate\n                  </Link>\n                  <Link to=\"/login\" className=\"text-neutral-500 hover:text-neutral-900 px-3 py-2 rounded-md text-sm font-medium transition-colors\">\n                    Login\n                  </Link>\n                  <Link to=\"/register\" className=\"bg-emerald-600 text-white hover:bg-emerald-700 px-4 py-2 rounded-md text-sm font-medium transition-colors shadow-sm\">\n                    Register\n                  </Link>\n                </>\n              )}\n            </div>\n          </div>\n        </div>\n      </header>\n\n      <main className=\"flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8\">\n        <Outlet />\n      </main>\n\n      <footer className=\"bg-white border-t border-neutral-200 mt-auto\">\n        <div className=\"max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6\">\n          <div className=\"text-center mb-4\">\n            <h4 className=\"text-neutral-900 font-semibold\">Victorious Christian Life Bible Course</h4>\n            <p className=\"text-sm text-neutral-600 mt-1\">\n              Principal Discipler: <a href=\"tel:08023024429\" className=\"text-emerald-600 hover:text-emerald-700\">08023024429</a>\n            </p>\n          </div>\n          <p className=\"text-center text-sm text-neutral-500\">\n            &copy; {new Date().getFullYear()} RCCG Victory Assembly, Jimeta Yola. All rights reserved.\n          </p>\n        </div>\n      </footer>\n    </div>\n  );\n}\n",
  "src/pages/Home.tsx": "import React from 'react';\nimport { Link } from 'react-router-dom';\nimport { BookOpen, Users, Award, Heart } from 'lucide-react';\nimport { motion } from 'motion/react';\n\nexport default function Home() {\n  return (\n    <motion.div\n      initial={{ opacity: 0, y: 20 }}\n      animate={{ opacity: 1, y: 0 }}\n      transition={{ duration: 0.5 }}\n      className=\"space-y-16\"\n    >\n      {/* Hero Section */}\n      <section className=\"text-center space-y-8 py-16\">\n        <h1 className=\"text-5xl md:text-6xl font-extrabold tracking-tight text-neutral-900\">\n          Victorious Christian Life <br className=\"hidden md:block\" />\n          <span className=\"text-emerald-600\">Bible Course</span>\n        </h1>\n        <p className=\"text-xl text-neutral-600 max-w-2xl mx-auto leading-relaxed\">\n          Welcome to the official discipleship platform of RCCG Victory Assembly. \n          Grow in your faith, connect with disciplers, and embark on a journey of spiritual maturity.\n        </p>\n        <div className=\"flex justify-center gap-4\">\n          <Link\n            to=\"/register\"\n            className=\"bg-emerald-600 text-white hover:bg-emerald-700 px-8 py-4 rounded-xl text-lg font-semibold transition-all shadow-lg hover:shadow-xl hover:-translate-y-1\"\n          >\n            Start Your Journey\n          </Link>\n          <Link\n            to=\"/login\"\n            className=\"bg-white text-neutral-700 hover:bg-neutral-50 border border-neutral-200 px-8 py-4 rounded-xl text-lg font-semibold transition-all shadow-sm hover:shadow-md\"\n          >\n            Login\n          </Link>\n        </div>\n      </section>\n\n      {/* Features Grid */}\n      <section className=\"grid md:grid-cols-2 lg:grid-cols-4 gap-8\">\n        <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 space-y-4\">\n          <div className=\"bg-emerald-100 w-14 h-14 rounded-xl flex items-center justify-center\">\n            <BookOpen className=\"h-7 w-7 text-emerald-600\" />\n          </div>\n          <h3 className=\"text-xl font-bold text-neutral-900\">Structured Learning</h3>\n          <p className=\"text-neutral-600 leading-relaxed\">\n            Three graduated levels of study: Foundation, Intermediate, and Advanced. 10 modules each to build a solid spiritual foundation.\n          </p>\n        </div>\n\n        <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 space-y-4\">\n          <div className=\"bg-emerald-100 w-14 h-14 rounded-xl flex items-center justify-center\">\n            <Users className=\"h-7 w-7 text-emerald-600\" />\n          </div>\n          <h3 className=\"text-xl font-bold text-neutral-900\">Personal Mentoring</h3>\n          <p className=\"text-neutral-600 leading-relaxed\">\n            Connect directly with your assigned Discipler. Ask questions, request prayers, and receive personalized guidance.\n          </p>\n        </div>\n\n        <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 space-y-4\">\n          <div className=\"bg-emerald-100 w-14 h-14 rounded-xl flex items-center justify-center\">\n            <Award className=\"h-7 w-7 text-emerald-600\" />\n          </div>\n          <h3 className=\"text-xl font-bold text-neutral-900\">Track Progress</h3>\n          <p className=\"text-neutral-600 leading-relaxed\">\n            Take quizzes after each module. Score 60% or higher to progress. Earn automatic certificates upon completing each level.\n          </p>\n        </div>\n\n        <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 space-y-4\">\n          <div className=\"bg-emerald-100 w-14 h-14 rounded-xl flex items-center justify-center\">\n            <Heart className=\"h-7 w-7 text-emerald-600\" />\n          </div>\n          <h3 className=\"text-xl font-bold text-neutral-900\">Donations</h3>\n          <p className=\"text-neutral-600 leading-relaxed\">\n            Support the ministry through Tithes, Offerings, Building Funds, Missions, and Welfare. Give cheerfully to advance the Kingdom.\n          </p>\n          <Link to=\"/donate\" className=\"inline-block mt-4 text-emerald-600 font-semibold hover:text-emerald-700\">\n            Give Now &rarr;\n          </Link>\n        </div>\n      </section>\n    </motion.div>\n  );\n}\n",
  "src/pages/Login.tsx": "import React, { useState } from 'react';\nimport { useNavigate, Link } from 'react-router-dom';\nimport { useAuth } from '../context/AuthContext';\nimport { motion } from 'motion/react';\nimport { BookOpen } from 'lucide-react';\n\nexport default function Login() {\n  const [email, setEmail] = useState('');\n  const [password, setPassword] = useState('');\n  const [error, setError] = useState('');\n  const { login } = useAuth();\n  const navigate = useNavigate();\n\n  const handleSubmit = async (e: React.FormEvent) => {\n    e.preventDefault();\n    setError('');\n\n    try {\n      const response = await fetch('/api/auth/login', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({ email, password }),\n      });\n\n      if (!response.ok) {\n        throw new Error('Invalid credentials');\n      }\n\n      const data = await response.json();\n      login(data.user);\n      navigate('/dashboard');\n    } catch (err: any) {\n      setError(err.message);\n    }\n  };\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, scale: 0.95 }}\n      animate={{ opacity: 1, scale: 1 }}\n      className=\"min-h-[80vh] flex items-center justify-center py-12 px-4 sm:px-6 lg:px-8\"\n    >\n      <div className=\"max-w-md w-full space-y-8 bg-white p-10 rounded-2xl shadow-xl border border-neutral-100\">\n        <div>\n          <div className=\"mx-auto h-12 w-12 bg-emerald-100 rounded-full flex items-center justify-center\">\n            <BookOpen className=\"h-6 w-6 text-emerald-600\" />\n          </div>\n          <h2 className=\"mt-6 text-center text-3xl font-extrabold text-neutral-900\">\n            Sign in to your account\n          </h2>\n          <p className=\"mt-2 text-center text-sm text-neutral-600\">\n            Or{' '}\n            <Link to=\"/register\" className=\"font-medium text-emerald-600 hover:text-emerald-500 transition-colors\">\n              start your discipleship journey\n            </Link>\n          </p>\n        </div>\n        <form className=\"mt-8 space-y-6\" onSubmit={handleSubmit}>\n          {error && (\n            <div className=\"bg-red-50 border-l-4 border-red-400 p-4 rounded-md\">\n              <p className=\"text-sm text-red-700\">{error}</p>\n            </div>\n          )}\n          <div className=\"rounded-md shadow-sm space-y-4\">\n            <div>\n              <label htmlFor=\"email-address\" className=\"sr-only\">\n                Email address\n              </label>\n              <input\n                id=\"email-address\"\n                name=\"email\"\n                type=\"email\"\n                autoComplete=\"email\"\n                required\n                className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                placeholder=\"Email address\"\n                value={email}\n                onChange={(e) => setEmail(e.target.value)}\n              />\n            </div>\n            <div>\n              <label htmlFor=\"password\" className=\"sr-only\">\n                Password\n              </label>\n              <input\n                id=\"password\"\n                name=\"password\"\n                type=\"password\"\n                autoComplete=\"current-password\"\n                required\n                className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                placeholder=\"Password\"\n                value={password}\n                onChange={(e) => setPassword(e.target.value)}\n              />\n            </div>\n          </div>\n\n          <div>\n            <button\n              type=\"submit\"\n              className=\"group relative w-full flex justify-center py-3 px-4 border border-transparent text-sm font-medium rounded-xl text-white bg-emerald-600 hover:bg-emerald-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 transition-all shadow-md hover:shadow-lg\"\n            >\n              Sign in\n            </button>\n          </div>\n        </form>\n      </div>\n    </motion.div>\n  );\n}\n",
  "src/pages/Register.tsx": "import React, { useState } from 'react';\nimport { useNavigate, Link } from 'react-router-dom';\nimport { useAuth } from '../context/AuthContext';\nimport { motion } from 'motion/react';\nimport { UserPlus } from 'lucide-react';\n\nexport default function Register() {\n  const [formData, setFormData] = useState({\n    name: '',\n    email: '',\n    phone: '',\n    password: '',\n    confirmPassword: '',\n    disciplerName: '',\n    disciplerPhone: '',\n    disciplerEmail: '',\n  });\n  const [error, setError] = useState('');\n  const { login } = useAuth();\n  const navigate = useNavigate();\n\n  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {\n    setFormData({ ...formData, [e.target.name]: e.target.value });\n  };\n\n  const handleSubmit = async (e: React.FormEvent) => {\n    e.preventDefault();\n    setError('');\n\n    if (formData.password !== formData.confirmPassword) {\n      setError('Passwords do not match');\n      return;\n    }\n\n    try {\n      const response = await fetch('/api/auth/register', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({\n          name: formData.name,\n          email: formData.email,\n          phone: formData.phone,\n          password: formData.password,\n          disciplerName: formData.disciplerName,\n          disciplerPhone: formData.disciplerPhone,\n          disciplerEmail: formData.disciplerEmail,\n        }),\n      });\n\n      if (!response.ok) {\n        const data = await response.json();\n        throw new Error(data.error || 'Registration failed');\n      }\n\n      const data = await response.json();\n      login(data.user);\n      navigate('/dashboard');\n    } catch (err: any) {\n      setError(err.message);\n    }\n  };\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, scale: 0.95 }}\n      animate={{ opacity: 1, scale: 1 }}\n      className=\"min-h-[80vh] flex items-center justify-center py-12 px-4 sm:px-6 lg:px-8\"\n    >\n      <div className=\"max-w-md w-full space-y-8 bg-white p-10 rounded-2xl shadow-xl border border-neutral-100\">\n        <div>\n          <div className=\"mx-auto h-12 w-12 bg-emerald-100 rounded-full flex items-center justify-center\">\n            <UserPlus className=\"h-6 w-6 text-emerald-600\" />\n          </div>\n          <h2 className=\"mt-6 text-center text-3xl font-extrabold text-neutral-900\">\n            Start Your Journey\n          </h2>\n          <p className=\"mt-2 text-center text-sm text-neutral-600\">\n            Already have an account?{' '}\n            <Link to=\"/login\" className=\"font-medium text-emerald-600 hover:text-emerald-500 transition-colors\">\n              Sign in\n            </Link>\n          </p>\n        </div>\n        <form className=\"mt-8 space-y-6\" onSubmit={handleSubmit}>\n          {error && (\n            <div className=\"bg-red-50 border-l-4 border-red-400 p-4 rounded-md\">\n              <p className=\"text-sm text-red-700\">{error}</p>\n            </div>\n          )}\n          <div className=\"rounded-md shadow-sm space-y-4\">\n            <div>\n              <label htmlFor=\"name\" className=\"sr-only\">Full Name</label>\n              <input\n                id=\"name\"\n                name=\"name\"\n                type=\"text\"\n                required\n                className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                placeholder=\"Full Name\"\n                value={formData.name}\n                onChange={handleChange}\n              />\n            </div>\n            <div>\n              <label htmlFor=\"email-address\" className=\"sr-only\">Email address</label>\n              <input\n                id=\"email-address\"\n                name=\"email\"\n                type=\"email\"\n                required\n                className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                placeholder=\"Email address\"\n                value={formData.email}\n                onChange={handleChange}\n              />\n            </div>\n            <div>\n              <label htmlFor=\"phone\" className=\"sr-only\">Phone Number</label>\n              <input\n                id=\"phone\"\n                name=\"phone\"\n                type=\"tel\"\n                required\n                className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                placeholder=\"Phone Number\"\n                value={formData.phone}\n                onChange={handleChange}\n              />\n            </div>\n            <div>\n              <label htmlFor=\"password\" className=\"sr-only\">Password</label>\n              <input\n                id=\"password\"\n                name=\"password\"\n                type=\"password\"\n                required\n                className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                placeholder=\"Password\"\n                value={formData.password}\n                onChange={handleChange}\n              />\n            </div>\n            <div>\n              <label htmlFor=\"confirmPassword\" className=\"sr-only\">Confirm Password</label>\n              <input\n                id=\"confirmPassword\"\n                name=\"confirmPassword\"\n                type=\"password\"\n                required\n                className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                placeholder=\"Confirm Password\"\n                value={formData.confirmPassword}\n                onChange={handleChange}\n              />\n            </div>\n\n            <div className=\"pt-4 border-t border-neutral-200\">\n              <h3 className=\"text-sm font-semibold text-neutral-700 mb-4\">Discipler Information</h3>\n              <div className=\"space-y-4\">\n                <div>\n                  <label htmlFor=\"disciplerName\" className=\"sr-only\">Discipler Full Name</label>\n                  <input\n                    id=\"disciplerName\"\n                    name=\"disciplerName\"\n                    type=\"text\"\n                    className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                    placeholder=\"Discipler Full Name\"\n                    value={formData.disciplerName}\n                    onChange={handleChange}\n                  />\n                </div>\n                <div>\n                  <label htmlFor=\"disciplerPhone\" className=\"sr-only\">Discipler Phone Number</label>\n                  <input\n                    id=\"disciplerPhone\"\n                    name=\"disciplerPhone\"\n                    type=\"tel\"\n                    className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                    placeholder=\"Discipler Phone Number\"\n                    value={formData.disciplerPhone}\n                    onChange={handleChange}\n                  />\n                </div>\n                <div>\n                  <label htmlFor=\"disciplerEmail\" className=\"sr-only\">Discipler Email Address</label>\n                  <input\n                    id=\"disciplerEmail\"\n                    name=\"disciplerEmail\"\n                    type=\"email\"\n                    className=\"appearance-none rounded-xl relative block w-full px-4 py-3 border border-neutral-300 placeholder-neutral-500 text-neutral-900 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 focus:z-10 sm:text-sm transition-all\"\n                    placeholder=\"Discipler Email Address\"\n                    value={formData.disciplerEmail}\n                    onChange={handleChange}\n                  />\n                </div>\n              </div>\n            </div>\n          </div>\n\n          <div>\n            <button\n              type=\"submit\"\n              className=\"group relative w-full flex justify-center py-3 px-4 border border-transparent text-sm font-medium rounded-xl text-white bg-emerald-600 hover:bg-emerald-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 transition-all shadow-md hover:shadow-lg\"\n            >\n              Register\n            </button>\n          </div>\n        </form>\n      </div>\n    </motion.div>\n  );\n}\n",
  "src/pages/Dashboard.tsx": "import React, { useEffect, useState } from 'react';\nimport { Link } from 'react-router-dom';\nimport { useAuth } from '../context/AuthContext';\nimport { motion } from 'motion/react';\nimport { BookOpen, Award, CheckCircle, Circle } from 'lucide-react';\n\ntype Course = {\n  id: number;\n  level: number;\n  title: string;\n  description: string;\n};\n\ntype Progress = {\n  module_id: number;\n  score: number;\n  passed: boolean;\n};\n\nexport default function Dashboard() {\n  const { user } = useAuth();\n  const [courses, setCourses] = useState<Course[]>([]);\n  const [progress, setProgress] = useState<Progress[]>([]);\n  const [loading, setLoading] = useState(true);\n\n  useEffect(() => {\n    const fetchData = async () => {\n      try {\n        const [coursesRes, progressRes] = await Promise.all([\n          fetch('/api/courses'),\n          fetch(`/api/users/${user?.id}/progress`)\n        ]);\n        \n        const coursesData = await coursesRes.json();\n        const progressData = await progressRes.json();\n        \n        setCourses(coursesData);\n        setProgress(progressData);\n      } catch (error) {\n        console.error('Error fetching data:', error);\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    if (user) {\n      fetchData();\n    }\n  }, [user]);\n\n  if (loading) {\n    return <div className=\"flex justify-center py-20\"><div className=\"animate-spin rounded-full h-12 w-12 border-b-2 border-emerald-600\"></div></div>;\n  }\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, y: 20 }}\n      animate={{ opacity: 1, y: 0 }}\n      className=\"space-y-8\"\n    >\n      <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 flex items-center justify-between\">\n        <div>\n          <h1 className=\"text-3xl font-bold text-neutral-900\">Welcome back, {user?.name}!</h1>\n          <p className=\"text-neutral-600 mt-2\">Continue your discipleship journey.</p>\n        </div>\n        <div className=\"hidden md:flex items-center gap-4 bg-emerald-50 px-6 py-4 rounded-xl\">\n          <BookOpen className=\"h-8 w-8 text-emerald-600\" />\n          <div>\n            <p className=\"text-sm text-emerald-800 font-medium\">Current Level</p>\n            <p className=\"text-2xl font-bold text-emerald-900\">Level 1</p>\n          </div>\n        </div>\n      </div>\n\n      <div className=\"grid md:grid-cols-3 gap-8\">\n        <div className=\"md:col-span-2 space-y-6\">\n          <h2 className=\"text-2xl font-bold text-neutral-900\">Your Courses</h2>\n          <div className=\"grid gap-6\">\n            {courses.map((course) => (\n              <Link\n                key={course.id}\n                to={`/courses/${course.id}`}\n                className=\"bg-white p-6 rounded-2xl shadow-sm border border-neutral-100 hover:shadow-md transition-all group flex items-start gap-6\"\n              >\n                <div className=\"bg-emerald-100 w-16 h-16 rounded-xl flex items-center justify-center flex-shrink-0 group-hover:bg-emerald-600 transition-colors\">\n                  <span className=\"text-2xl font-bold text-emerald-600 group-hover:text-white\">\n                    {course.level}\n                  </span>\n                </div>\n                <div className=\"flex-1\">\n                  <h3 className=\"text-xl font-bold text-neutral-900 group-hover:text-emerald-600 transition-colors\">\n                    {course.title}\n                  </h3>\n                  <p className=\"text-neutral-600 mt-1\">{course.description}</p>\n                  <div className=\"mt-4 flex items-center gap-2 text-sm text-emerald-600 font-medium\">\n                    <span>View Course Modules</span>\n                    <span className=\"group-hover:translate-x-1 transition-transform\">→</span>\n                  </div>\n                </div>\n              </Link>\n            ))}\n          </div>\n        </div>\n\n        <div className=\"space-y-6\">\n          <h2 className=\"text-2xl font-bold text-neutral-900\">Daily Devotion</h2>\n          <div className=\"bg-white p-6 rounded-2xl shadow-sm border border-neutral-100 space-y-4\">\n            <p className=\"text-lg font-serif italic text-neutral-800 leading-relaxed\">\n              \"But grow in the grace and knowledge of our Lord and Savior Jesus Christ. To him be glory both now and forever! Amen.\"\n            </p>\n            <p className=\"text-sm font-bold text-emerald-600 uppercase tracking-wider\">\n              2 Peter 3:18\n            </p>\n          </div>\n\n          <h2 className=\"text-2xl font-bold text-neutral-900 pt-4\">Certificates</h2>\n          <div className=\"bg-white p-6 rounded-2xl shadow-sm border border-neutral-100 flex flex-col items-center justify-center text-center space-y-4 min-h-[200px]\">\n            <Award className=\"h-12 w-12 text-neutral-300\" />\n            <p className=\"text-neutral-500\">Complete Level 1 to earn your first certificate.</p>\n          </div>\n        </div>\n      </div>\n    </motion.div>\n  );\n}\n",
  "src/pages/AdminDashboard.tsx": "import React, { useEffect, useState } from 'react';\nimport { useAuth } from '../context/AuthContext';\nimport { motion } from 'motion/react';\nimport { Users, BookOpen, MessageSquare, Settings } from 'lucide-react';\n\ntype User = {\n  id: number;\n  name: string;\n  email: string;\n  phone: string;\n  role: string;\n  created_at: string;\n};\n\nexport default function AdminDashboard() {\n  const { user } = useAuth();\n  const [users, setUsers] = useState<User[]>([]);\n  const [loading, setLoading] = useState(true);\n  const [activeTab, setActiveTab] = useState('users');\n\n  useEffect(() => {\n    const fetchUsers = async () => {\n      try {\n        const res = await fetch('/api/admin/users');\n        if (res.ok) {\n          const data = await res.json();\n          setUsers(data);\n        }\n      } catch (error) {\n        console.error('Error fetching users:', error);\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    if (user?.role === 'admin' || user?.role === 'discipler') {\n      fetchUsers();\n    }\n  }, [user]);\n\n  if (loading) {\n    return <div className=\"flex justify-center py-20\"><div className=\"animate-spin rounded-full h-12 w-12 border-b-2 border-emerald-600\"></div></div>;\n  }\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, y: 20 }}\n      animate={{ opacity: 1, y: 0 }}\n      className=\"space-y-8\"\n    >\n      <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 flex items-center justify-between\">\n        <div>\n          <h1 className=\"text-3xl font-bold text-neutral-900\">Admin Dashboard</h1>\n          <p className=\"text-neutral-600 mt-2\">Manage disciples, courses, and messages.</p>\n        </div>\n        <div className=\"hidden md:flex items-center gap-4 bg-emerald-50 px-6 py-4 rounded-xl\">\n          <Settings className=\"h-8 w-8 text-emerald-600\" />\n          <div>\n            <p className=\"text-sm text-emerald-800 font-medium\">Role</p>\n            <p className=\"text-2xl font-bold text-emerald-900 capitalize\">{user?.role}</p>\n          </div>\n        </div>\n      </div>\n\n      <div className=\"flex gap-4 border-b border-neutral-200 pb-4\">\n        <button\n          onClick={() => setActiveTab('users')}\n          className={`flex items-center gap-2 px-6 py-3 rounded-xl font-semibold transition-colors ${\n            activeTab === 'users' ? 'bg-emerald-600 text-white' : 'bg-white text-neutral-600 hover:bg-neutral-50 border border-neutral-200'\n          }`}\n        >\n          <Users className=\"h-5 w-5\" />\n          Users\n        </button>\n        <button\n          onClick={() => setActiveTab('courses')}\n          className={`flex items-center gap-2 px-6 py-3 rounded-xl font-semibold transition-colors ${\n            activeTab === 'courses' ? 'bg-emerald-600 text-white' : 'bg-white text-neutral-600 hover:bg-neutral-50 border border-neutral-200'\n          }`}\n        >\n          <BookOpen className=\"h-5 w-5\" />\n          Courses\n        </button>\n        <button\n          onClick={() => setActiveTab('messages')}\n          className={`flex items-center gap-2 px-6 py-3 rounded-xl font-semibold transition-colors ${\n            activeTab === 'messages' ? 'bg-emerald-600 text-white' : 'bg-white text-neutral-600 hover:bg-neutral-50 border border-neutral-200'\n          }`}\n        >\n          <MessageSquare className=\"h-5 w-5\" />\n          Messages\n        </button>\n      </div>\n\n      {activeTab === 'users' && (\n        <div className=\"bg-white rounded-2xl shadow-sm border border-neutral-100 overflow-hidden\">\n          <div className=\"overflow-x-auto\">\n            <table className=\"min-w-full divide-y divide-neutral-200\">\n              <thead className=\"bg-neutral-50\">\n                <tr>\n                  <th scope=\"col\" className=\"px-6 py-4 text-left text-xs font-bold text-neutral-500 uppercase tracking-wider\">\n                    Name\n                  </th>\n                  <th scope=\"col\" className=\"px-6 py-4 text-left text-xs font-bold text-neutral-500 uppercase tracking-wider\">\n                    Contact\n                  </th>\n                  <th scope=\"col\" className=\"px-6 py-4 text-left text-xs font-bold text-neutral-500 uppercase tracking-wider\">\n                    Role\n                  </th>\n                  <th scope=\"col\" className=\"px-6 py-4 text-left text-xs font-bold text-neutral-500 uppercase tracking-wider\">\n                    Joined\n                  </th>\n                </tr>\n              </thead>\n              <tbody className=\"bg-white divide-y divide-neutral-200\">\n                {users.map((u) => (\n                  <tr key={u.id} className=\"hover:bg-neutral-50 transition-colors\">\n                    <td className=\"px-6 py-4 whitespace-nowrap\">\n                      <div className=\"flex items-center\">\n                        <div className=\"flex-shrink-0 h-10 w-10 bg-emerald-100 rounded-full flex items-center justify-center\">\n                          <span className=\"text-emerald-700 font-bold\">{u.name.charAt(0)}</span>\n                        </div>\n                        <div className=\"ml-4\">\n                          <div className=\"text-sm font-medium text-neutral-900\">{u.name}</div>\n                        </div>\n                      </div>\n                    </td>\n                    <td className=\"px-6 py-4 whitespace-nowrap\">\n                      <div className=\"text-sm text-neutral-900\">{u.email}</div>\n                      <div className=\"text-sm text-neutral-500\">{u.phone || 'N/A'}</div>\n                    </td>\n                    <td className=\"px-6 py-4 whitespace-nowrap\">\n                      <span className={`px-3 py-1 inline-flex text-xs leading-5 font-semibold rounded-full ${\n                        u.role === 'admin' ? 'bg-purple-100 text-purple-800' :\n                        u.role === 'discipler' ? 'bg-blue-100 text-blue-800' :\n                        'bg-emerald-100 text-emerald-800'\n                      }`}>\n                        {u.role}\n                      </span>\n                    </td>\n                    <td className=\"px-6 py-4 whitespace-nowrap text-sm text-neutral-500\">\n                      {new Date(u.created_at).toLocaleDateString()}\n                    </td>\n                  </tr>\n                ))}\n              </tbody>\n            </table>\n          </div>\n        </div>\n      )}\n\n      {activeTab === 'courses' && (\n        <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 text-center py-20\">\n          <BookOpen className=\"h-16 w-16 text-neutral-300 mx-auto mb-4\" />\n          <h3 className=\"text-xl font-bold text-neutral-900\">Course Management</h3>\n          <p className=\"text-neutral-500 mt-2\">Upload study materials, manage modules, and create quizzes.</p>\n          <button className=\"mt-6 bg-emerald-600 text-white hover:bg-emerald-700 px-6 py-3 rounded-xl font-semibold transition-colors\">\n            Add New Module\n          </button>\n        </div>\n      )}\n\n      {activeTab === 'messages' && (\n        <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 text-center py-20\">\n          <MessageSquare className=\"h-16 w-16 text-neutral-300 mx-auto mb-4\" />\n          <h3 className=\"text-xl font-bold text-neutral-900\">Messaging Hub</h3>\n          <p className=\"text-neutral-500 mt-2\">Send broadcast messages, schedule devotionals, and manage announcements.</p>\n          <div className=\"mt-6 flex justify-center gap-4\">\n            <button className=\"bg-emerald-600 text-white hover:bg-emerald-700 px-6 py-3 rounded-xl font-semibold transition-colors\">\n              New Broadcast\n            </button>\n            <button className=\"bg-white text-neutral-700 hover:bg-neutral-50 border border-neutral-200 px-6 py-3 rounded-xl font-semibold transition-colors\">\n              Schedule Devotional\n            </button>\n          </div>\n        </div>\n      )}\n    </motion.div>\n  );\n}\n",
  "src/pages/CourseView.tsx": "import React, { useEffect, useState } from 'react';\nimport { useParams, Link } from 'react-router-dom';\nimport { useAuth } from '../context/AuthContext';\nimport { motion } from 'motion/react';\nimport { CheckCircle, Circle, Lock, PlayCircle } from 'lucide-react';\n\ntype Module = {\n  id: number;\n  module_number: number;\n  title: string;\n  content: string;\n};\n\ntype Progress = {\n  module_id: number;\n  score: number;\n  passed: boolean;\n};\n\nexport default function CourseView() {\n  const { id } = useParams<{ id: string }>();\n  const { user } = useAuth();\n  const [modules, setModules] = useState<Module[]>([]);\n  const [progress, setProgress] = useState<Progress[]>([]);\n  const [loading, setLoading] = useState(true);\n\n  useEffect(() => {\n    const fetchData = async () => {\n      try {\n        const [modulesRes, progressRes] = await Promise.all([\n          fetch(`/api/courses/${id}/modules`),\n          fetch(`/api/users/${user?.id}/progress`)\n        ]);\n        \n        const modulesData = await modulesRes.json();\n        const progressData = await progressRes.json();\n        \n        setModules(modulesData);\n        setProgress(progressData);\n      } catch (error) {\n        console.error('Error fetching data:', error);\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    if (user && id) {\n      fetchData();\n    }\n  }, [user, id]);\n\n  if (loading) {\n    return <div className=\"flex justify-center py-20\"><div className=\"animate-spin rounded-full h-12 w-12 border-b-2 border-emerald-600\"></div></div>;\n  }\n\n  // Determine which module is currently unlocked\n  // A module is unlocked if the previous module is passed, or if it's the first module\n  const isModuleUnlocked = (index: number) => {\n    if (index === 0) return true;\n    const prevModuleId = modules[index - 1].id;\n    const prevProgress = progress.find(p => p.module_id === prevModuleId);\n    return prevProgress?.passed === true;\n  };\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, y: 20 }}\n      animate={{ opacity: 1, y: 0 }}\n      className=\"space-y-8 max-w-4xl mx-auto\"\n    >\n      <div className=\"bg-emerald-900 text-white p-10 rounded-3xl shadow-lg flex flex-col md:flex-row items-center justify-between gap-8\">\n        <div className=\"space-y-4\">\n          <h1 className=\"text-4xl font-extrabold tracking-tight\">Level {id} Modules</h1>\n          <p className=\"text-emerald-100 text-lg max-w-xl leading-relaxed\">\n            Complete each module and score at least 60% on the quiz to unlock the next one.\n          </p>\n        </div>\n        <div className=\"bg-emerald-800 p-6 rounded-2xl text-center min-w-[150px]\">\n          <p className=\"text-emerald-200 text-sm font-bold uppercase tracking-wider mb-2\">Progress</p>\n          <p className=\"text-4xl font-bold\">\n            {progress.filter(p => p.passed && modules.some(m => m.id === p.module_id)).length} / {modules.length}\n          </p>\n        </div>\n      </div>\n\n      <div className=\"space-y-4\">\n        {modules.map((module, index) => {\n          const unlocked = isModuleUnlocked(index);\n          const moduleProgress = progress.find(p => p.module_id === module.id);\n          const passed = moduleProgress?.passed;\n\n          return (\n            <div\n              key={module.id}\n              className={`bg-white p-6 rounded-2xl border transition-all flex items-center gap-6 ${\n                unlocked ? 'border-neutral-200 hover:shadow-md hover:border-emerald-200' : 'border-neutral-100 opacity-75 bg-neutral-50'\n              }`}\n            >\n              <div className=\"flex-shrink-0\">\n                {passed ? (\n                  <CheckCircle className=\"h-8 w-8 text-emerald-500\" />\n                ) : unlocked ? (\n                  <Circle className=\"h-8 w-8 text-emerald-200\" />\n                ) : (\n                  <Lock className=\"h-8 w-8 text-neutral-300\" />\n                )}\n              </div>\n              \n              <div className=\"flex-1\">\n                <div className=\"flex items-center gap-3 mb-1\">\n                  <span className=\"text-sm font-bold text-emerald-600 uppercase tracking-wider\">\n                    Module {module.module_number}\n                  </span>\n                  {moduleProgress && (\n                    <span className={`text-xs font-bold px-2 py-1 rounded-full ${passed ? 'bg-emerald-100 text-emerald-800' : 'bg-red-100 text-red-800'}`}>\n                      Score: {moduleProgress.score.toFixed(0)}%\n                    </span>\n                  )}\n                </div>\n                <h3 className={`text-xl font-bold ${unlocked ? 'text-neutral-900' : 'text-neutral-500'}`}>\n                  {module.title}\n                </h3>\n              </div>\n\n              <div>\n                {unlocked ? (\n                  <Link\n                    to={`/modules/${module.id}`}\n                    className=\"flex items-center gap-2 bg-emerald-50 text-emerald-700 hover:bg-emerald-100 px-6 py-3 rounded-xl font-semibold transition-colors\"\n                  >\n                    <PlayCircle className=\"h-5 w-5\" />\n                    <span>{passed ? 'Review' : 'Start'}</span>\n                  </Link>\n                ) : (\n                  <button disabled className=\"flex items-center gap-2 bg-neutral-100 text-neutral-400 px-6 py-3 rounded-xl font-semibold cursor-not-allowed\">\n                    <Lock className=\"h-5 w-5\" />\n                    <span>Locked</span>\n                  </button>\n                )}\n              </div>\n            </div>\n          );\n        })}\n        {modules.length === 0 && (\n          <div className=\"text-center py-12 text-neutral-500 bg-white rounded-2xl border border-neutral-100\">\n            No modules available for this course yet.\n          </div>\n        )}\n      </div>\n    </motion.div>\n  );\n}\n",
  "src/pages/ModuleView.tsx": "import React, { useEffect, useState } from 'react';\nimport { useParams, useNavigate } from 'react-router-dom';\nimport { useAuth } from '../context/AuthContext';\nimport { motion } from 'motion/react';\nimport { ArrowLeft, CheckCircle, XCircle, BookOpen } from 'lucide-react';\n\ntype Quiz = {\n  id: number;\n  question: string;\n  options: string[];\n};\n\ntype Module = {\n  id: number;\n  course_id: number;\n  module_number: number;\n  title: string;\n  content: string;\n  quizzes: Quiz[];\n};\n\nexport default function ModuleView() {\n  const { id } = useParams<{ id: string }>();\n  const { user } = useAuth();\n  const navigate = useNavigate();\n  const [module, setModule] = useState<Module | null>(null);\n  const [loading, setLoading] = useState(true);\n  const [answers, setAnswers] = useState<Record<number, number>>({});\n  const [submitting, setSubmitting] = useState(false);\n  const [result, setResult] = useState<{ score: number; passed: boolean } | null>(null);\n\n  useEffect(() => {\n    const fetchModule = async () => {\n      try {\n        const res = await fetch(`/api/modules/${id}`);\n        if (res.ok) {\n          const data = await res.json();\n          setModule(data);\n        }\n      } catch (error) {\n        console.error('Error fetching module:', error);\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    if (id) {\n      fetchModule();\n    }\n  }, [id]);\n\n  const handleOptionSelect = (quizId: number, optionIndex: number) => {\n    setAnswers(prev => ({ ...prev, [quizId]: optionIndex }));\n  };\n\n  const handleSubmit = async () => {\n    if (!module || !user) return;\n    \n    if (Object.keys(answers).length < module.quizzes.length) {\n      alert('Please answer all questions before submitting.');\n      return;\n    }\n\n    setSubmitting(true);\n    try {\n      const res = await fetch(`/api/modules/${id}/submit`, {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({ userId: user.id, answers }),\n      });\n\n      if (res.ok) {\n        const data = await res.json();\n        setResult(data);\n      } else {\n        alert('Failed to submit quiz');\n      }\n    } catch (error) {\n      console.error('Error submitting quiz:', error);\n    } finally {\n      setSubmitting(false);\n    }\n  };\n\n  if (loading) {\n    return <div className=\"flex justify-center py-20\"><div className=\"animate-spin rounded-full h-12 w-12 border-b-2 border-emerald-600\"></div></div>;\n  }\n\n  if (!module) {\n    return <div className=\"text-center py-20 text-neutral-500\">Module not found.</div>;\n  }\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, y: 20 }}\n      animate={{ opacity: 1, y: 0 }}\n      className=\"max-w-3xl mx-auto space-y-8\"\n    >\n      <button\n        onClick={() => navigate(-1)}\n        className=\"flex items-center gap-2 text-neutral-500 hover:text-neutral-900 transition-colors\"\n      >\n        <ArrowLeft className=\"h-5 w-5\" />\n        Back to Course\n      </button>\n\n      <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100\">\n        <div className=\"flex items-center gap-4 mb-6\">\n          <div className=\"bg-emerald-100 w-12 h-12 rounded-xl flex items-center justify-center\">\n            <BookOpen className=\"h-6 w-6 text-emerald-600\" />\n          </div>\n          <div>\n            <h1 className=\"text-3xl font-bold text-neutral-900\">{module.title}</h1>\n            <p className=\"text-emerald-600 font-medium\">Module {module.module_number}</p>\n          </div>\n        </div>\n        \n        <div className=\"prose prose-emerald max-w-none text-neutral-700 leading-relaxed\">\n          {module.content.split('\\\\n').map((paragraph, idx) => (\n            <p key={idx} className=\"mb-4\">{paragraph}</p>\n          ))}\n        </div>\n      </div>\n\n      {module.quizzes.length > 0 && (\n        <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 space-y-8\">\n          <h2 className=\"text-2xl font-bold text-neutral-900 border-b border-neutral-100 pb-4\">Quiz</h2>\n          \n          {result ? (\n            <div className={`p-8 rounded-2xl text-center ${result.passed ? 'bg-emerald-50 border border-emerald-200' : 'bg-red-50 border border-red-200'}`}>\n              {result.passed ? (\n                <CheckCircle className=\"h-16 w-16 text-emerald-500 mx-auto mb-4\" />\n              ) : (\n                <XCircle className=\"h-16 w-16 text-red-500 mx-auto mb-4\" />\n              )}\n              <h3 className={`text-2xl font-bold mb-2 ${result.passed ? 'text-emerald-900' : 'text-red-900'}`}>\n                {result.passed ? 'Congratulations!' : 'Keep Trying!'}\n              </h3>\n              <p className={`text-lg ${result.passed ? 'text-emerald-700' : 'text-red-700'}`}>\n                You scored {result.score.toFixed(0)}%. {result.passed ? 'You have passed this module.' : 'You need 60% to pass.'}\n              </p>\n              <button\n                onClick={() => navigate(`/courses/${module.course_id}`)}\n                className={`mt-6 px-6 py-3 rounded-xl font-semibold transition-colors ${\n                  result.passed \n                    ? 'bg-emerald-600 text-white hover:bg-emerald-700' \n                    : 'bg-red-600 text-white hover:bg-red-700'\n                }`}\n              >\n                Return to Course\n              </button>\n            </div>\n          ) : (\n            <div className=\"space-y-8\">\n              {module.quizzes.map((quiz, qIndex) => (\n                <div key={quiz.id} className=\"space-y-4\">\n                  <p className=\"font-bold text-lg text-neutral-900\">\n                    {qIndex + 1}. {quiz.question}\n                  </p>\n                  <div className=\"space-y-3\">\n                    {quiz.options.map((option, oIndex) => (\n                      <label\n                        key={oIndex}\n                        className={`flex items-center p-4 rounded-xl border cursor-pointer transition-all ${\n                          answers[quiz.id] === oIndex\n                            ? 'border-emerald-500 bg-emerald-50'\n                            : 'border-neutral-200 hover:bg-neutral-50'\n                        }`}\n                      >\n                        <input\n                          type=\"radio\"\n                          name={`quiz-${quiz.id}`}\n                          value={oIndex}\n                          checked={answers[quiz.id] === oIndex}\n                          onChange={() => handleOptionSelect(quiz.id, oIndex)}\n                          className=\"h-5 w-5 text-emerald-600 focus:ring-emerald-500 border-neutral-300\"\n                        />\n                        <span className=\"ml-3 text-neutral-700\">{option}</span>\n                      </label>\n                    ))}\n                  </div>\n                </div>\n              ))}\n              \n              <button\n                onClick={handleSubmit}\n                disabled={submitting || Object.keys(answers).length < module.quizzes.length}\n                className=\"w-full bg-emerald-600 text-white hover:bg-emerald-700 disabled:bg-neutral-300 disabled:cursor-not-allowed px-6 py-4 rounded-xl font-bold text-lg transition-all shadow-md\"\n              >\n                {submitting ? 'Submitting...' : 'Submit Quiz'}\n              </button>\n            </div>\n          )}\n        </div>\n      )}\n    </motion.div>\n  );\n}\n",
  "src/pages/Donate.tsx": "import React, { useState } from 'react';\nimport { motion } from 'motion/react';\nimport { Heart, CheckCircle } from 'lucide-react';\nimport { useAuth } from '../context/AuthContext';\n\nexport default function Donate() {\n  const { user } = useAuth();\n  const [amount, setAmount] = useState('');\n  const [category, setCategory] = useState('Offering');\n  const [name, setName] = useState(user?.name || '');\n  const [email, setEmail] = useState(user?.email || '');\n  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');\n  const [errorMessage, setErrorMessage] = useState('');\n\n  const donationCategories = [\n    { name: 'Offering', account: '2012345678', bank: 'Ecobank' },\n    { name: 'Tithe', account: '2034567812', bank: 'Guaranty Trust Bank' },\n    { name: 'Thanksgiving', account: '2056781234', bank: 'Zenith Bank' },\n    { name: 'Building Fund', account: '2078123456', bank: 'Access Bank' },\n    { name: 'Missions', account: '2090123456', bank: 'United Bank for Africa (UBA)' },\n    { name: 'Welfare', account: '2112345678', bank: 'First Bank of Nigeria' },\n    { name: 'VCLBC Support', account: '2134567890', bank: 'Fidelity Bank' }\n  ];\n\n  const selectedCategoryDetails = donationCategories.find(c => c.name === category);\n\n  const handleSubmit = async (e: React.FormEvent) => {\n    e.preventDefault();\n    setStatus('loading');\n    setErrorMessage('');\n\n    try {\n      const res = await fetch('/api/donations', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json' },\n        body: JSON.stringify({\n          userId: user?.id,\n          name,\n          email,\n          amount: parseFloat(amount),\n          category\n        })\n      });\n\n      if (!res.ok) {\n        const data = await res.json();\n        throw new Error(data.error || 'Failed to process donation');\n      }\n\n      setStatus('success');\n    } catch (err: any) {\n      setStatus('error');\n      setErrorMessage(err.message);\n    }\n  };\n\n  if (status === 'success') {\n    return (\n      <motion.div\n        initial={{ opacity: 0, scale: 0.95 }}\n        animate={{ opacity: 1, scale: 1 }}\n        className=\"max-w-md mx-auto bg-white p-8 rounded-2xl shadow-sm border border-neutral-100 text-center\"\n      >\n        <CheckCircle className=\"h-16 w-16 text-emerald-500 mx-auto mb-4\" />\n        <h2 className=\"text-2xl font-bold text-neutral-900 mb-2\">Thank You!</h2>\n        <p className=\"text-neutral-600 mb-6\">\n          Your {category.toLowerCase()} of ₦{amount} has been received successfully. God bless you!\n        </p>\n        <button\n          onClick={() => {\n            setStatus('idle');\n            setAmount('');\n          }}\n          className=\"bg-emerald-600 text-white hover:bg-emerald-700 px-6 py-3 rounded-xl font-semibold transition-colors w-full\"\n        >\n          Make Another Donation\n        </button>\n      </motion.div>\n    );\n  }\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, y: 20 }}\n      animate={{ opacity: 1, y: 0 }}\n      className=\"max-w-xl mx-auto\"\n    >\n      <div className=\"text-center mb-8\">\n        <div className=\"bg-emerald-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4\">\n          <Heart className=\"h-8 w-8 text-emerald-600\" />\n        </div>\n        <h1 className=\"text-3xl font-bold text-neutral-900 mb-2\">Support the Ministry</h1>\n        <p className=\"text-neutral-600\">\n          \"Every man according as he purposeth in his heart, so let him give; not grudgingly, or of necessity: for God loveth a cheerful giver.\" - 2 Corinthians 9:7\n        </p>\n      </div>\n\n      <div className=\"bg-white p-8 rounded-2xl shadow-sm border border-neutral-100\">\n        <form onSubmit={handleSubmit} className=\"space-y-6\">\n          {status === 'error' && (\n            <div className=\"bg-red-50 text-red-600 p-4 rounded-xl text-sm border border-red-100\">\n              {errorMessage}\n            </div>\n          )}\n\n          {!user && (\n            <>\n              <div>\n                <label className=\"block text-sm font-medium text-neutral-700 mb-2\">\n                  Full Name\n                </label>\n                <input\n                  type=\"text\"\n                  required\n                  value={name}\n                  onChange={(e) => setName(e.target.value)}\n                  className=\"w-full px-4 py-3 rounded-xl border border-neutral-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all\"\n                  placeholder=\"John Doe\"\n                />\n              </div>\n              <div>\n                <label className=\"block text-sm font-medium text-neutral-700 mb-2\">\n                  Email Address\n                </label>\n                <input\n                  type=\"email\"\n                  required\n                  value={email}\n                  onChange={(e) => setEmail(e.target.value)}\n                  className=\"w-full px-4 py-3 rounded-xl border border-neutral-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all\"\n                  placeholder=\"john@example.com\"\n                />\n              </div>\n            </>\n          )}\n\n          <div>\n            <label className=\"block text-sm font-medium text-neutral-700 mb-2\">\n              Donation Category\n            </label>\n            <select\n              value={category}\n              onChange={(e) => setCategory(e.target.value)}\n              className=\"w-full px-4 py-3 rounded-xl border border-neutral-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all bg-white\"\n            >\n              {donationCategories.map(cat => (\n                <option key={cat.name} value={cat.name}>{cat.name}</option>\n              ))}\n            </select>\n          </div>\n\n          {selectedCategoryDetails && (\n            <div className=\"bg-emerald-50 p-4 rounded-xl border border-emerald-100\">\n              <h4 className=\"text-sm font-semibold text-emerald-900 mb-2\">Church Account Details</h4>\n              <div className=\"space-y-1 text-sm text-emerald-800\">\n                <p><span className=\"font-medium\">Bank:</span> {selectedCategoryDetails.bank}</p>\n                <p><span className=\"font-medium\">Account Number:</span> {selectedCategoryDetails.account}</p>\n                <p><span className=\"font-medium\">Account Name:</span> RCCG Victory Assembly</p>\n              </div>\n            </div>\n          )}\n\n          <div>\n            <label className=\"block text-sm font-medium text-neutral-700 mb-2\">\n              Amount (₦)\n            </label>\n            <input\n              type=\"number\"\n              required\n              min=\"100\"\n              step=\"100\"\n              value={amount}\n              onChange={(e) => setAmount(e.target.value)}\n              className=\"w-full px-4 py-3 rounded-xl border border-neutral-200 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all\"\n              placeholder=\"5000\"\n            />\n          </div>\n\n          <button\n            type=\"submit\"\n            disabled={status === 'loading'}\n            className=\"w-full bg-emerald-600 text-white hover:bg-emerald-700 px-6 py-4 rounded-xl font-semibold transition-all shadow-sm hover:shadow-md disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2\"\n          >\n            {status === 'loading' ? 'Processing...' : `Donate ₦${amount || '0'}`}\n          </button>\n        </form>\n      </div>\n    </motion.div>\n  );\n}\n",
  "src/context/AuthContext.tsx": "import React, { createContext, useContext, useState, useEffect } from 'react';\n\ntype User = {\n  id: number;\n  name: string;\n  email: string;\n  role: 'admin' | 'discipler' | 'disciple';\n};\n\ntype AuthContextType = {\n  user: User | null;\n  login: (user: User) => void;\n  logout: () => void;\n};\n\nconst AuthContext = createContext<AuthContextType | undefined>(undefined);\n\nexport const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {\n  const [user, setUser] = useState<User | null>(() => {\n    const storedUser = localStorage.getItem('user');\n    return storedUser ? JSON.parse(storedUser) : null;\n  });\n\n  const login = (userData: User) => {\n    setUser(userData);\n    localStorage.setItem('user', JSON.stringify(userData));\n  };\n\n  const logout = () => {\n    setUser(null);\n    localStorage.removeItem('user');\n  };\n\n  return (\n    <AuthContext.Provider value={{ user, login, logout }}>\n      {children}\n    </AuthContext.Provider>\n  );\n};\n\nexport const useAuth = () => {\n  const context = useContext(AuthContext);\n  if (context === undefined) {\n    throw new Error('useAuth must be used within an AuthProvider');\n  }\n  return context;\n};\n",
  "vite.config.ts": "import tailwindcss from '@tailwindcss/vite';\nimport react from '@vitejs/plugin-react';\nimport path from 'path';\nimport {defineConfig, loadEnv} from 'vite';\n\nexport default defineConfig(({mode}) => {\n  const env = loadEnv(mode, '.', '');\n  return {\n    plugins: [react(), tailwindcss()],\n    define: {\n      'process.env.GEMINI_API_KEY': JSON.stringify(env.GEMINI_API_KEY),\n    },\n    resolve: {\n      alias: {\n        '@': path.resolve(__dirname, '.'),\n      },\n    },\n    server: {\n      // HMR is disabled in AI Studio via DISABLE_HMR env var.\n      // Do not modifyâfile watching is disabled to prevent flickering during agent edits.\n      hmr: process.env.DISABLE_HMR !== 'true',\n    },\n  };\n});\n"
};

